SELECT user_id FROM conversation_participant
WHERE conversation_id = #{conversationId} AND user_id != #{userId}
LIMIT 1

SELECT c.* FROM conversation c
JOIN conversation_participant cp1 ON cp1.conversation_id = c.id AND cp1.user_id = #{userId1}
JOIN conversation_participant cp2 ON cp2.conversation_id = c.id AND cp2.user_id = #{userId2}
LIMIT 1
